import{_ as p,C as u,o,c,a3 as d,b as i,w as t,a,E as l,a4 as s,j as r}from"./chunks/framework.C49Ar5GK.js";const R=JSON.parse('{"title":"整体架构：控制面、数据面与计算面","description":"用三层心智模型理解 veRL V1 的 TaskRunner、PPOTrainer、AgentLoop、TransferQueue、WorkerGroup 与权重同步","frontmatter":{"title":"整体架构：控制面、数据面与计算面","description":"用三层心智模型理解 veRL V1 的 TaskRunner、PPOTrainer、AgentLoop、TransferQueue、WorkerGroup 与权重同步","lesson":{"stage":"04 · 源码","order":14,"time":"40–55 分钟","level":"源码入门","question":"谁决定下一步做什么、谁真正占 GPU 计算、样本与权重又分别怎样流动？"}},"headers":[],"relativePath":"internals/architecture.md","filePath":"internals/architecture.md","lastUpdated":null}'),A={name:"internals/architecture.md"};function h(T,e,f,m,E,L){const n=u("Mermaid");return o(),c("div",null,[e[2]||(e[2]=d('<h1 id="整体架构-控制面、数据面与计算面" tabindex="-1">整体架构：控制面、数据面与计算面 <a class="header-anchor" href="#整体架构-控制面、数据面与计算面" aria-label="Permalink to &quot;整体架构：控制面、数据面与计算面&quot;">​</a></h1><p>当前 V1 可以用三层理解：Hydra/Ray driver 决定“做什么”，WorkerGroup 与 LLM server 执行“怎么算”，TransferQueue 保存“样本在哪里”。</p><h2 id="先用人话-导演、演员与道具仓库" tabindex="-1">先用人话：导演、演员与道具仓库 <a class="header-anchor" href="#先用人话-导演、演员与道具仓库" aria-label="Permalink to &quot;先用人话：导演、演员与道具仓库&quot;">​</a></h2><ul><li>控制面像导演：排顺序、叫哪个角色行动，但自己通常不做大模型矩阵计算；</li><li>计算面像演员：actor/critic/rollout/reward worker 真正占用 GPU/CPU；</li><li>数据面像编号道具仓库：TransferQueue 保存值，trainer 常拿的是 <code>KVBatchMeta</code> 这张领料单；</li><li>权重同步像换剧本：训练 actor 写出新版本，再交给推理 server 用于下一轮生成。</li></ul><p>这个比喻只负责建立边界。接下来用真实组件和调用关系校准。</p><h2 id="组件图" tabindex="-1">组件图 <a class="header-anchor" href="#组件图" aria-label="Permalink to &quot;组件图&quot;">​</a></h2>',6)),(o(),i(s,null,{default:t(()=>[l(n,{id:"mermaid-37",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20CLI%5BHydra%20CLI%20%2F%20YAML%5D%20--%3E%20MAIN%5Bmain_ppo.py%5D%0A%20%20%20%20MAIN%20--%3E%20RAY%5BRay%20TaskRunnerV1%5D%0A%0A%20%20%20%20subgraph%20CTRL%5B%E6%8E%A7%E5%88%B6%E9%9D%A2%EF%BC%9ATaskRunner%20%2F%20PPOTrainer%5D%0A%20%20%20%20%20%20RAY%20--%3E%20TR%5BPPOTrainer%5D%0A%20%20%20%20%20%20TR%20--%3E%20RB%5BReplayBuffer%5D%0A%20%20%20%20%20%20TR%20--%3E%20ALM%5BAgentLoopManager%5D%0A%20%20%20%20%20%20TR%20--%3E%20CM%5BCheckpointEngineManager%5D%0A%20%20%20%20%20%20TR%20--%3E%20RM%5BRewardLoopManager%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20COMPUTE%5B%E8%AE%A1%E7%AE%97%E9%9D%A2%EF%BC%9ARay%20actors%20%2F%20GPU%5D%0A%20%20%20%20%20%20AWG%5BActor%20%2F%20Reference%20WorkerGroup%5D%0A%20%20%20%20%20%20CWG%5BCritic%20WorkerGroup%20%E5%8F%AF%E9%80%89%5D%0A%20%20%20%20%20%20LLM%5BLLM%20Server%20replicas%3Cbr%2F%3EvLLM%20%2F%20SGLang%20%E7%AD%89%5D%0A%20%20%20%20%20%20RW%5BReward%20workers%20%2F%20RM%20server%20%E5%8F%AF%E9%80%89%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20DATA%5B%E6%95%B0%E6%8D%AE%E9%9D%A2%5D%0A%20%20%20%20%20%20DL%5BDataset%20%2F%20DataLoader%5D%0A%20%20%20%20%20%20TQ%5B(TransferQueue%3Cbr%2F%3ETensorDict%20values%20%2B%20tags)%5D%0A%20%20%20%20end%0A%0A%20%20%20%20DL%20--%3E%20TR%0A%20%20%20%20ALM%20--%3E%20LLM%0A%20%20%20%20ALM%20--%3E%20TQ%0A%20%20%20%20RB%20--%3E%20TQ%0A%20%20%20%20TR%20--%3E%20AWG%0A%20%20%20%20TR%20--%3E%20CWG%0A%20%20%20%20RM%20--%3E%20RW%0A%20%20%20%20RW%20--%3E%20TQ%0A%20%20%20%20CM%20--%3E%20AWG%0A%20%20%20%20CM%20--%3E%20LLM%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[a(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=d('<p>图的关键不是框的数量，而是两条边界：生成结果由 AgentLoop 写入 TQ，trainer 主要拿 <code>KVBatchMeta</code> 句柄；权重更新发生在训练 WorkerGroup，随后由 checkpoint engine 同步到 LLM server replicas。</p><h2 id="组件职责" tabindex="-1">组件职责 <a class="header-anchor" href="#组件职责" aria-label="Permalink to &quot;组件职责&quot;">​</a></h2><h3 id="main-ppo-py-与-taskrunner" tabindex="-1"><code>main_ppo.py</code> 与 TaskRunner <a class="header-anchor" href="#main-ppo-py-与-taskrunner" aria-label="Permalink to &quot;`main_ppo.py` 与 TaskRunner&quot;">​</a></h3><p>Hydra 组合配置、校验角色需求、初始化 Ray，并让远端 <code>TaskRunnerV1</code> 运行。TaskRunner 强制启用 TransferQueue，选择 <code>sync</code>、<code>colocate_async</code> 或 <code>separate_async</code> trainer，最后负责关闭 TQ。</p><h3 id="ppotrainer" tabindex="-1"><code>PPOTrainer</code> <a class="header-anchor" href="#ppotrainer" aria-label="Permalink to &quot;`PPOTrainer`&quot;">​</a></h3><p>它是单控制器上的编排者，不是所有大张量的永久容器。它初始化 tokenizer/dataloader、资源池、训练 WorkerGroup、reward loop、LLM servers 和 checkpoint engine；在 <code>fit()</code> 中按 step 安排验证、rollout、训练、保存、指标与清理。</p><h3 id="agentloop-与-llm-server" tabindex="-1">AgentLoop 与 LLM server <a class="header-anchor" href="#agentloop-与-llm-server" aria-label="Permalink to &quot;AgentLoop 与 LLM server&quot;">​</a></h3><p>AgentLoop 面向“一个 prompt 怎样与模型/工具/环境交互”。单轮回答只是最简单情况；多轮 agent 可以产出同一 session 的多个 output。LLM server 提供高吞吐生成，AgentLoop 将输出整理成统一字段后写 TQ。</p><h3 id="transferqueue-与-replaybuffer" tabindex="-1">TransferQueue 与 ReplayBuffer <a class="header-anchor" href="#transferqueue-与-replaybuffer" aria-label="Permalink to &quot;TransferQueue 与 ReplayBuffer&quot;">​</a></h3><p>TQ 的 tag 存轻量状态和长度/版本元数据，value 存 trajectory 字段。ReplayBuffer 同步 tag，等待完整 prompt group，优先取较旧的可用 prompt，并对超过版本阈值的轨迹执行 <code>drop</code> 或 <code>wait</code>。</p><h3 id="workergroup" tabindex="-1">WorkerGroup <a class="header-anchor" href="#workergroup" aria-label="Permalink to &quot;WorkerGroup&quot;">​</a></h3><p>训练计算由 Ray WorkerGroup 分发到数据并行/张量并行等后端。Actor、reference 与 rollout 可以共享物理资源或模型载入方式；critic、reward model、teacher 是否出现取决于配置。</p><h2 id="三种-trainer-mode" tabindex="-1">三种 trainer mode <a class="header-anchor" href="#三种-trainer-mode" aria-label="Permalink to &quot;三种 trainer mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>资源关系</th><th>参数同步</th><th>适合先理解什么</th></tr></thead><tbody><tr><td><code>sync</code></td><td>trainer 与 rollout 共置</td><td>每个 step 更新后同步</td><td>最清晰的正确性主线</td></tr><tr><td><code>colocate_async</code></td><td>共置但生成/训练流水化</td><td>允许一定异步</td><td>空闲时间与 staleness 权衡</td></tr><tr><td><code>separate_async</code></td><td>训练和 rollout 分离</td><td><code>parameter_sync_step</code> 控制频率</td><td>独立扩缩容与更强异步</td></tr></tbody></table><p>异步不是单纯“更快”的开关：它改变样本来自哪个权重版本、缓存容量、反压位置和故障可见性。第一次读源码建议固定 <code>sync</code>，再对比两个异步子类重写的生命周期钩子。</p><h2 id="一次数据与权重的闭环" tabindex="-1">一次数据与权重的闭环 <a class="header-anchor" href="#一次数据与权重的闭环" aria-label="Permalink to &quot;一次数据与权重的闭环&quot;">​</a></h2>',16)),(o(),i(s,null,{default:t(()=>[l(n,{id:"mermaid-145",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20P%5Bprompt%5D%20--%3E%20G%5BLLM%20rollout%5D%0A%20%20%20%20G%20--%3E%20T%5B(trajectory%20in%20TQ)%5D%0A%20%20%20%20T%20--%3E%20S%5Breward%20%2F%20log-prob%20%2F%20value%5D%0A%20%20%20%20S%20--%3E%20U%5Bactor%20%2F%20critic%20update%5D%0A%20%20%20%20U%20--%3E%20W%5Bnew%20weights%5D%0A%20%20%20%20W%20--%3E%20G%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[a(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=r("p",null,"数据方向是顺时针，权重方向从训练 worker 回到生成 server。调试时先判断问题属于哪条流：样本没有到 TQ、字段写错、训练没有更新，还是新权重没有同步。",-1)),e[5]||(e[5]=r("h2",{id:"通关检查",tabindex:"-1"},[a("通关检查 "),r("a",{class:"header-anchor",href:"#通关检查","aria-label":'Permalink to "通关检查"'},"​")],-1)),e[6]||(e[6]=r("p",null,"遮住组件图，分别画“数据箭头”和“权重箭头”。在图中圈出只做控制的对象、真正持有模型参数的进程、保存轨迹值的系统，以及只携带 keys/tags 的句柄。若把 PPOTrainer 画成亲自持有所有 GPU tensor，需要回看边界。",-1)),e[7]||(e[7]=r("p",null,[a("下一步："),r("a",{href:"./entry-and-init"},"入口与初始化"),a("。")],-1))])}const B=p(A,[["render",h]]);export{R as __pageData,B as default};
